<Stats id="monster-tulpa--stats" atts={[20,16,14,10,17,8]} bab={3} cmb={8} cmd={26} feats={["Dodge","Improved Initiative","Improved Unarmed Strike","Power Attack","Stunning Fist","Toughness",["Weapon Focus"," (unarmed strike)"]]} skills={{"acro":{"b":11},"bluff":{"b":0,"x":"+8 vs. its creator"},"diplo":{"b":0,"x":"+8 vs. its creator"},"sm":{"b":11,"x":"+19 vs. its creator"},"stl":{"b":11}}} racial="+8 Bluff, Diplomacy, Intimidate, and Sense Motive vs. its creator" lang={["C"]} sq="creator link, fast movement, high jump, ki pool (5 points, magic), maneuver training, mental form (DC 12), slow fall 20 ft., sustained by thought" />
