<Defense id="monster-vampire_vampire_warrior--defense" ac={[25,15,20]} mod="+8 armor, +4 Dex, +1 dodge, +2 natural" hp={[78,"7d10+35"]} fh="5" fort="+9" ref="+7" will="+4 (+2 vs. fear); +2 vs. poison" def={[["bravery 2prayer scroll","bravery +2prayer scroll"]]} chanRes="+4" dr="10/magic and slashing" immune={<Link to="/umr/undead_traits">undead traits</Link>} resist="cold 20" weak={["jiang-shi weaknesses"]} />
